import { useEffect, useState } from "react";
import { useLocation } from "react-router-dom";

export default function MyBugs() {
  const [bugs, setBugs] = useState([]);
  const location = useLocation();

  const status = new URLSearchParams(location.search).get("status");

  useEffect(() => {
    const token = localStorage.getItem("token");

    fetch("http://localhost:5000/api/bugs/hacker/bugs", {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then(res => res.json())
      .then(data => {
        if (status) {
          setBugs(data.filter(bug => bug.status === status));
        } else {
          setBugs(data);
        }
      });
  }, [status]);

  return (
    <div className="hacker-dashboard">
      <h1>
        {status ? status.toUpperCase() : "MY"} BUGS
      </h1>

      {bugs.length === 0 && <p>No bugs found.</p>}

      {bugs.map(bug => (
        <div key={bug._id} className="bug-card">
          <h3>{bug.title}</h3>
          <p>Status: {bug.status}</p>
          <p>Severity: {bug.severity}</p>
        </div>
      ))}
    </div>
  );
}
